/// Wrap a `IHtmlVisitor` vtable into a `VisitorHandle` suitable for the
/// generated options-field setter (e.g. `ConversionOptionsBuilder.visitor`).
/// The returned handle owns the vtable's function pointers and must be
/// released with the matching `htm_visitor_handle_free` once the
/// containing options object is no longer needed.
pub fn html_visitor_handle_from_vtable(callbacks: c.HTMHtmVisitorCallbacks) ?VisitorHandle {
    var _cb = callbacks;
    return @ptrCast(c.htm_html_visitor_handle_from_callbacks(&_cb));
}

/// Build an `IHtmlVisitor` vtable for a concrete Zig type `T`.
///
/// `T` must implement every method of `HtmlVisitor` as a plain Zig function.
/// Each slot is wrapped in a `callconv(.C)` thunk that casts `user_data`
/// back to `*T` and forwards the call.
///
/// # Usage
/// ```zig
/// const vtable = make_html_visitor_vtable(MyType, &my_instance);
/// _ = register_html_visitor("my-impl", vtable, &my_instance, &out_error);
/// ```
pub fn make_html_visitor_vtable(comptime T: type, instance: *T) IHtmlVisitor {
    _ = instance; // instance is passed as user_data by the caller
    return IHtmlVisitor{
        .visit_text = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _text: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
                _ = out_result;
                return self.visit_text(_ctx, _text);
            }
        }.thunk,

        .visit_element_start = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
                _ = out_result;
                return self.visit_element_start(_ctx);
            }
        }.thunk,

        .visit_element_end = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _output: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
                _ = out_result;
                return self.visit_element_end(_ctx, _output);
            }
        }.thunk,

        .visit_link = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _href: [*c]const u8, _text: [*c]const u8, _title: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
                _ = out_result;
                return self.visit_link(_ctx, _href, _text, _title);
            }
        }.thunk,

        .visit_image = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _src: [*c]const u8, _alt: [*c]const u8, _title: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
                _ = out_result;
                return self.visit_image(_ctx, _src, _alt, _title);
            }
        }.thunk,

        .visit_heading = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _level: u32, _text: [*c]const u8, _id: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
