        .visit_code_block = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _lang: [*c]const u8, _code: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
