        }.thunk,

        .visit_code_inline = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _code: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
