            }
        }.thunk,

        .visit_list_item = struct {
            fn thunk(ud: ?*anyopaque, _ctx: [*c]const u8, _ordered: i32, _marker: [*c]const u8, _text: [*c]const u8, out_result: ?*?[*c]u8) callconv(.C) [*c]const u8 {
                const self: *T = @ptrCast(@alignCast(ud));
